295	njs_int_t
296	njs_lexer_init(njs_vm_t *vm, njs_lexer_t *lexer, njs_str_t *file,
297	    u_char *start, u_char *end)
298	{
299	    lexer->file = *file;
300	    lexer->start = start;
301	    lexer->end = end;
302	    lexer->line = 1;
303	    lexer->vm = vm;
304	
305	    njs_queue_init(&lexer->preread);
306	
307	    return njs_lexer_in_stack_init(lexer);
308	}
