310	
311	njs_int_t
312	njs_lexer_in_stack_init(njs_lexer_t *lexer)
313	{
314	    lexer->in_stack_size = 128;
315	    lexer->in_stack = njs_mp_zalloc(lexer->vm->mem_pool, lexer->in_stack_size);
316	    if (lexer->in_stack == NULL) {
317	        return NJS_ERROR;
318	    }
319	
320	    lexer->in_stack_ptr = 0;
321	
322	    return NJS_OK;
323	}
324	
325	
326	njs_int_t
327	njs_lexer_in_stack_push(njs_lexer_t *lexer)
328	{
329	    u_char  *tmp;
330	    size_t  size;
331	
332	    lexer->in_stack_ptr++;
333	
334	    if (lexer->in_stack_ptr < lexer->in_stack_size) {
335	        lexer->in_stack[lexer->in_stack_ptr] = 0;
336	        return NJS_OK;
337	    }
338	
339	    /* Realloc in_stack, it is up to higher layer generate error if any. */
340	
341	    size = lexer->in_stack_size;
342	    lexer->in_stack_size = size * 2;
343	
344	    tmp = njs_mp_alloc(lexer->vm->mem_pool, size * 2);
345	    if (tmp == NULL) {
346	        return NJS_ERROR;
347	    }
348	
349	    memcpy(tmp, lexer->in_stack, size);
350	    memset(&tmp[size], 0, size);
351	
352	    njs_mp_free(lexer->vm->mem_pool, lexer->in_stack);
353	    lexer->in_stack = tmp;
354	
355	    return NJS_OK;
356	}
357	
358	
359	void
360	njs_lexer_in_stack_pop(njs_lexer_t *lexer)
361	{
362	    /**
363	     * if in_stack_ptr <= 0 do nothing, it is up to higher layer
364	     * generate error.
365	     */
366	
367	    if (lexer->in_stack_ptr > 0) {
368	        lexer->in_stack_ptr--;
369	    }
370	}
