387	njs_inline njs_int_t
388	njs_lexer_in_stack(njs_lexer_t *lexer, njs_lexer_token_t  *token)
389	{
390	    switch (token->type) {
391	    case NJS_TOKEN_OPEN_PARENTHESIS:
392	    case NJS_TOKEN_OPEN_BRACKET:
393	    case NJS_TOKEN_OPEN_BRACE:
394	        return njs_lexer_in_stack_push(lexer);
395	
396	    case NJS_TOKEN_CLOSE_PARENTHESIS:
397	    case NJS_TOKEN_CLOSE_BRACKET:
398	    case NJS_TOKEN_CLOSE_BRACE:
399	        njs_lexer_in_stack_pop(lexer);
400	        break;
401	
402	    default:
403	        break;
404	    }
405	
406	    return NJS_OK;
407	}
