409	
410	njs_inline njs_lexer_token_t *
411	njs_lexer_next_token(njs_lexer_t *lexer)
412	{
413	    njs_int_t          ret;
414	    njs_lexer_token_t  *token;
415	
416	    token = njs_mp_zalloc(lexer->vm->mem_pool, sizeof(njs_lexer_token_t));
417	    if (njs_slow_path(token == NULL)) {
418	        return NULL;
419	    }
420	
421	    do {
422	        ret = njs_lexer_make_token(lexer, token);
423	        if (njs_slow_path(ret != NJS_OK)) {
424	            return NULL;
425	        }
426	
427	    } while (token->type == NJS_TOKEN_COMMENT);
428	
429	    njs_queue_insert_tail(&lexer->preread, &token->link);
430	
431	    ret = njs_lexer_in_stack(lexer, token);
432	    if (njs_slow_path(ret != NJS_OK)) {
433	        return NULL;
434	    }
435	
436	    return token;
437	}
