439	
440	njs_lexer_token_t *
441	njs_lexer_token(njs_lexer_t *lexer, njs_bool_t with_end_line)
442	{
443	    njs_queue_link_t   *lnk;
444	    njs_lexer_token_t  *token;
445	
446	    lnk = njs_queue_first(&lexer->preread);
447	
448	    while (lnk != njs_queue_head(&lexer->preread)) {
449	        token = njs_queue_link_data(lnk, njs_lexer_token_t, link);
450	
451	        if (!with_end_line && token->type == NJS_TOKEN_LINE_END) {
452	            lexer->prev_type = token->type;
453	
454	            lnk = njs_queue_next(&token->link);
455	            continue;
456	        }
457	
458	        return token;
459	    }
460	
461	    do {
462	        token = njs_lexer_next_token(lexer);
463	        if (token == NULL) {
464	            return NULL;
465	        }
466	
467	        if (!with_end_line && token->type == NJS_TOKEN_LINE_END) {
468	            lexer->prev_type = token->type;
469	            continue;
470	        }
471	
472	        break;
473	
474	    } while (1);
475	
476	    return token;
477	}
