480	njs_lexer_token_t *
481	njs_lexer_peek_token(njs_lexer_t *lexer, njs_lexer_token_t *current,
482	    njs_bool_t with_end_line)
483	{
484	    njs_queue_link_t   *lnk;
485	    njs_lexer_token_t  *token;
486	
487	    lnk = njs_queue_next(&current->link);
488	
489	    while (lnk != njs_queue_head(&lexer->preread)) {
490	        token = njs_queue_link_data(lnk, njs_lexer_token_t, link);
491	
492	        if (!with_end_line && token->type == NJS_TOKEN_LINE_END) {
493	            lnk = njs_queue_next(&token->link);
494	            continue;
495	        }
496	
497	        return token;
498	    }
499	
500	    do {
501	        token = njs_lexer_next_token(lexer);
502	        if (token == NULL) {
503	            return NULL;
504	        }
505	
506	        if (!with_end_line && token->type == NJS_TOKEN_LINE_END) {
507	            continue;
508	        }
509	
510	        break;
511	
512	    } while (1);
513	
514	    return token;
515	}
