518	void
519	njs_lexer_consume_token(njs_lexer_t *lexer, unsigned length)
520	{
521	    njs_queue_link_t   *lnk;
522	    njs_lexer_token_t  *token;
523	
524	    while (length > 0) {
525	        lnk = njs_queue_first(&lexer->preread);
526	        token = njs_queue_link_data(lnk, njs_lexer_token_t, link);
527	
528	        lexer->prev_type = token->type;
529	
530	        if (token->type != NJS_TOKEN_LINE_END) {
531	            length--;
532	        }
533	
534	        njs_queue_remove(lnk);
535	
536	        njs_mp_free(lexer->vm->mem_pool, token);
537	    }
538	}
