540	
541	njs_int_t
542	njs_lexer_make_token(njs_lexer_t *lexer, njs_lexer_token_t *token)
543	{
544	    u_char                c, *p;
545	    uint32_t              cp;
546	    njs_unicode_decode_t  ctx;
547	
548	    c = ' ';
549	
550	    njs_utf8_decode_init(&ctx);
551	
552	    while (lexer->start < lexer->end) {
553	        c = *lexer->start;
554	
555	        if (njs_fast_path(!(c & 0x80))) {
556	            lexer->start++;
557	
558	            if (njs_tokens[c] != NJS_TOKEN_SPACE) {
559	                break;
560	            }
561	
562	        } else {
563	
564	            /* Unicode. */
565	
566	            cp = njs_utf8_decode(&ctx, (const u_char **) &lexer->start,
567	                                 lexer->end);
568	            if (njs_slow_path(cp > NJS_UNICODE_MAX_CODEPOINT)) {
569	                c = '\0';
570	                break;
571	            }
572	
573	            if (!njs_utf8_is_whitespace(cp)) {
574	                break;
575	            }
576	        }
577	    }
578	
579	    token->type = njs_tokens[c];
580	    token->line = lexer->line;
581	
582	    switch (token->type) {
583	
584	    case NJS_TOKEN_LETTER:
585	        return njs_lexer_word(lexer, token);
586	
587	    case NJS_TOKEN_DOUBLE_QUOTE:
588	    case NJS_TOKEN_SINGLE_QUOTE:
589	        njs_lexer_string(lexer, token, c);
590	        break;
591	
592	    case NJS_TOKEN_DOT:
593	        p = lexer->start;
594	
595	        if (p + 1 < lexer->end
596	            && njs_tokens[p[0]] == NJS_TOKEN_DOT
597	            && njs_tokens[p[1]] == NJS_TOKEN_DOT)
598	        {
599	            token->text.start = lexer->start - 1;
600	            token->text.length = (p - token->text.start) + 2;
601	
602	            token->type = NJS_TOKEN_ELLIPSIS;
603	
604	            lexer->start += 2;
605	
606	            return NJS_OK;
607	        }
608	
609	        if (p == lexer->end || njs_tokens[*p] != NJS_TOKEN_DIGIT) {
610	            token->text.start = lexer->start - 1;
611	            token->text.length = p - token->text.start;
612	
613	            token->type = NJS_TOKEN_DOT;
614	
615	            return NJS_OK;
616	        }
617	
618	        /* Fall through. */
619	
620	    case NJS_TOKEN_DIGIT:
621	        njs_lexer_number(lexer, token);
622	        break;
623	
624	    case NJS_TOKEN_DIVISION:
625	        njs_lexer_division(lexer, token);
626	        break;
627	
628	    case NJS_TOKEN_ASSIGNMENT:
629	        njs_lexer_multi(lexer, token, njs_assignment_token,
630	                        njs_nitems(njs_assignment_token));
631	        break;
632	
633	    case NJS_TOKEN_ADDITION:
634	        njs_lexer_multi(lexer, token, njs_addition_token,
635	                        njs_nitems(njs_addition_token));
636	        break;
637	
638	    case NJS_TOKEN_SUBTRACTION:
639	        njs_lexer_multi(lexer, token, njs_substraction_token,
640	                        njs_nitems(njs_substraction_token));
641	        break;
642	
643	    case NJS_TOKEN_MULTIPLICATION:
644	        njs_lexer_multi(lexer, token, njs_multiplication_token,
645	                        njs_nitems(njs_multiplication_token));
646	        break;
647	
648	    case NJS_TOKEN_REMAINDER:
649	        njs_lexer_multi(lexer, token, njs_remainder_token,
650	                        njs_nitems(njs_remainder_token));
651	        break;
652	
653	    case NJS_TOKEN_BITWISE_AND:
654	        njs_lexer_multi(lexer, token, njs_bitwise_and_token,
655	                        njs_nitems(njs_bitwise_and_token));
656	        break;
657	
658	    case NJS_TOKEN_BITWISE_XOR:
659	        njs_lexer_multi(lexer, token, njs_bitwise_xor_token,
660	                        njs_nitems(njs_bitwise_xor_token));
661	        break;
662	
663	    case NJS_TOKEN_BITWISE_OR:
664	        njs_lexer_multi(lexer, token, njs_bitwise_or_token,
665	                        njs_nitems(njs_bitwise_or_token));
666	        break;
667	
668	    case NJS_TOKEN_LOGICAL_NOT:
669	        njs_lexer_multi(lexer, token, njs_logical_not_token,
670	                        njs_nitems(njs_logical_not_token));
671	        break;
672	
673	    case NJS_TOKEN_LESS:
674	        njs_lexer_multi(lexer, token, njs_less_token,
675	                        njs_nitems(njs_less_token));
676	        break;
677	
678	    case NJS_TOKEN_GREATER:
679	        njs_lexer_multi(lexer, token, njs_greater_token,
680	                        njs_nitems(njs_greater_token));
681	        break;
682	
683	    case NJS_TOKEN_CONDITIONAL:
684	        njs_lexer_multi(lexer, token, njs_conditional_token,
685	                        njs_nitems(njs_conditional_token));
686	        break;
687	
688	    case NJS_TOKEN_SPACE:
689	        token->type = NJS_TOKEN_END;
690	        return NJS_OK;
691	
692	    case NJS_TOKEN_LINE_END:
693	        lexer->line++;
694	
695	        /* Fall through. */
696	
697	    default:
698	        token->text.start = lexer->start - 1;
699	        token->text.length = lexer->start - token->text.start;
700	
701	        break;
702	    }
703	
704	    return NJS_OK;
705	}
706	
707	
708	static njs_int_t
709	njs_lexer_word(njs_lexer_t *lexer, njs_lexer_token_t *token)
710	{
711	    u_char             *p, c;
712	    uint32_t           hash_id;
713	    njs_int_t          ret;
714	    njs_value_t        value;
715	    const njs_value_t  *entry;
716	
717	    /* TODO: UTF-8 */
718	
719	    static const uint8_t letter_digit[32]  njs_aligned(32) = {
720	        0x00, 0x00, 0x00, 0x00, /* 0000 0000 0000 0000  0000 0000 0000 0000 */
721	
722	                                /* '&%$ #"!  /.-, |*)(  7654 3210 ?>=< ;:98 */
723	        0x10, 0x00, 0xff, 0x03, /* 0001 0000 0000 0000  1111 1111 0000 0011 */
724	
725	                                /* GFED CBA@ ONML KJIH  WVUT SRQP _^]\ [ZYX */
726	        0xfe, 0xff, 0xff, 0x87, /* 1111 1110 1111 1111  1111 1111 1000 0111 */
727	
728	                                /* gfed cba` onml kjih  wvut srqp  ~}| {zyx */
729	        0xfe, 0xff, 0xff, 0x07, /* 1111 1110 1111 1111  1111 1111 0000 0111 */
730	
731	        0x00, 0x00, 0x00, 0x00, /* 0000 0000 0000 0000  0000 0000 0000 0000 */
732	        0x00, 0x00, 0x00, 0x00, /* 0000 0000 0000 0000  0000 0000 0000 0000 */
733	        0x00, 0x00, 0x00, 0x00, /* 0000 0000 0000 0000  0000 0000 0000 0000 */
734	        0x00, 0x00, 0x00, 0x00, /* 0000 0000 0000 0000  0000 0000 0000 0000 */
735	    };
736	
737	    token->text.start = lexer->start - 1;
738	
739	    hash_id = njs_djb_hash_add(NJS_DJB_HASH_INIT, *token->text.start);
740	
741	    for (p = lexer->start; p < lexer->end; p++) {
742	        c = *p;
743	
744	        if ((letter_digit[c / 8] & (1 << (c & 7))) == 0) {
745	            break;
746	        }
747	
748	        hash_id = njs_djb_hash_add(hash_id, c);
749	    }
750	
751	    token->text.length = p - token->text.start;
752	    lexer->start = p;
753	
754	    entry = njs_atom_find(lexer->vm, token->text.start, token->text.length,
755	                          hash_id);
756	    if (entry == NULL) {
757	        ret = njs_string_create(lexer->vm, &value, token->text.start,
758	                                token->text.length);
759	        if (njs_slow_path(ret != NJS_OK)) {
760	            return NJS_ERROR;
761	        }
762	
763	        entry = njs_atom_add(lexer->vm, &value, hash_id);
764	        if (njs_slow_path(entry == NULL)) {
765	            return NJS_ERROR;
766	        }
767	    }
768	
769	    if (entry->string.token_type == NJS_KEYWORD_TYPE_UNDEF) {
770	        token->type = NJS_TOKEN_NAME;
771	        token->keyword_type = NJS_KEYWORD_TYPE_UNDEF;
772	
773	    } else {
774	        token->type = entry->string.token_id;
775	        token->keyword_type = entry->string.token_type;
776	    }
777	
778	    token->atom_id = entry->atom_id;
779	
780	    return NJS_OK;
781	}
