783	
784	static void
785	njs_lexer_string(njs_lexer_t *lexer, njs_lexer_token_t *token, u_char quote)
786	{
787	    u_char      *p, c;
788	    njs_bool_t  escape;
789	
790	    escape = 0;
791	
792	    p = lexer->start;
793	    token->text.start = p;
794	
795	    while (p < lexer->end) {
796	
797	        c = *p++;
798	
799	        if (c == '\\') {
800	            if (p == lexer->end) {
801	                break;
802	            }
803	
804	            p++;
805	
806	            /* Line continuation. */
807	            if (p < lexer->end && p[-1] == '\r' && p[0] == '\n') {
808	                p++;
809	            }
810	
811	            escape = 1;
812	
813	            continue;
814	        }
815	
816	        /* Line terminator. */
817	        if (c == '\r' || c == '\n') {
818	            break;
819	        }
820	
821	        if (c == quote) {
822	            lexer->start = p;
823	            token->text.length = (p - 1) - token->text.start;
824	
825	            token->type = (escape == 0) ? NJS_TOKEN_STRING
826	                                        : NJS_TOKEN_ESCAPE_STRING;
827	            return;
828	        }
829	    }
830	
831	    token->text.start--;
832	    token->text.length = p - token->text.start;
833	
834	    token->type = NJS_TOKEN_UNTERMINATED_STRING;
835	}
836	
837	
838	static void
839	njs_lexer_number(njs_lexer_t *lexer, njs_lexer_token_t *token)
840	{
841	    int           flags;
842	    const u_char  *p;
843	
844	    token->text.start = lexer->start - 1;
845	    p = token->text.start;
846	
847	    flags = JS_ATOD_ACCEPT_BIN_OCT | JS_ATOD_ACCEPT_UNDERSCORES;
848	
849	    if (p[0] == '0' && (p + 1) < lexer->end) {
850	        /* Legacy octal literal. */
851	
852	        if (p[1] == '_' || (p[1] >= '0' && p[1] <= '9')) {
853	            for (p++; p < lexer->end; p++) {
854	                if (*p == '_' || (*p >= '0' && *p <= '9')) {
855	                    continue;
856	                }
857	
858	                break;
859	            }
860	
861	            goto illegal_token;
862	        }
863	
864	        if ((p[1] == 'x' || p[1] == 'X'
865	                || p[1] == 'b' || p[1] == 'B'
866	                || p[1] == 'o' || p[1] == 'O'))
867	        {
868	            flags |= JS_ATOD_INT_ONLY;
869	        }
870	    }
871	
872	    token->number = njs_atod((const char *) p, (const char **) &p, 0, flags);
873	
874	#define njs_continuation_char(c)                                              \
875	     (njs_tokens[c] == NJS_TOKEN_LETTER || njs_tokens[c] == NJS_TOKEN_DIGIT)
876	
877	    if (isnan(token->number) || (p < lexer->end && njs_continuation_char(*p))) {
878	        while (p < lexer->end) {
879	            if (!njs_continuation_char(*p)) {
880	                break;
881	            }
882	
883	            p++;
884	        }
885	
886	        goto illegal_token;
887	    }
888	
889	    lexer->start = (u_char *) p;
890	    token->text.length = p - token->text.start;
891	
892	    token->type = NJS_TOKEN_NUMBER;
893	
894	    return;
895	
896	illegal_token:
897	
898	    token->text.length = p - token->text.start;
899	
900	    token->type = NJS_TOKEN_ILLEGAL;
901	}
902	
903	
904	static void
905	njs_lexer_multi(njs_lexer_t *lexer, njs_lexer_token_t *token,
906	    const njs_lexer_multi_t *multi, size_t length)
907	{
908	    u_char  c;
909	
910	    token->line = lexer->line;
911	    token->text.start = lexer->start - 1;
912	
913	    while (length != 0 && multi != NULL && lexer->start < lexer->end) {
914	        c = lexer->start[0];
915	
916	        if (c == multi->symbol) {
917	            lexer->start++;
918	
919	            token->type = multi->token;
920	
921	            if (multi->count == 0) {
922	                break;
923	            }
924	
925	            length = multi->count;
926	            multi = multi->next;
927	
928	        } else {
929	            length--;
930	            multi++;
931	        }
932	    }
933	
934	    token->text.length = lexer->start - token->text.start;
935	}
936	
937	
938	static void
939	njs_lexer_division(njs_lexer_t *lexer, njs_lexer_token_t *token)
940	{
941	    u_char  c, *p;
942	
943	    token->text.start = lexer->start - 1;
944	
945	    if (lexer->start >= lexer->end) {
946	        goto done;
947	    }
948	
949	    c = lexer->start[0];
950	
951	    if (c == '/') {
952	        lexer->start++;
953	
954	        for (p = lexer->start; p < lexer->end; p++) {
955	
956	            if (*p == '\n' || (p + 1) == lexer->end) {
957	                lexer->start = p + 1;
958	                lexer->line++;
959	
960	                token->type = NJS_TOKEN_LINE_END;
961	
962	                goto done;
963	            }
964	        }
965	
966	    } else if (c == '*') {
967	        lexer->start++;
968	
969	        for (p = lexer->start; p < lexer->end; p++) {
970	
971	            if (*p == '\n') {
972	                lexer->line++;
973	                continue;
974	            }
975	
976	            if (*p == '*') {
977	                if (p + 1 < lexer->end && p[1] == '/') {
978	                    lexer->start = p + 2;
979	
980	                    token->type = NJS_TOKEN_COMMENT;
981	
982	                    goto done;
983	                }
984	            }
985	        }
986	
987	        token->type = NJS_TOKEN_ILLEGAL;
988	
989	    } else if (c == '=') {
990	        lexer->start++;
991	
992	        token->type = NJS_TOKEN_DIVISION_ASSIGNMENT;
993	    }
994	
995	done:
996	
997	    token->text.length = lexer->start - token->text.start;
998	}
